   244	                    "notify_lsp_current_file_opened: no metadata for buffer {:?}",
   245	                    self.active_buffer()
   246	                );
   247	                return;
   248	            }
   249	        };
   250	
   251	        if !metadata.lsp_enabled {
   252	            tracing::debug!("notify_lsp_current_file_opened: LSP disabled for this buffer");
   253	            return;
   254	        }
   255	
   256	        // Get file path for LSP spawn
   257	        let file_path = metadata.file_path().cloned();
   258	
   259	        // Get the URI (computed once in with_file)
