                    Ok(path) => match self.open_file(&path) {
                        Ok(_) => {
                            self.set_status_message(format!("init.ts: {}", path.display()));
                        }
                        Err(e) => {
                            self.set_status_message(format!("init.ts: open failed: {e}"));
